## Overview

Replace the four raw-number stats bar with a semantic status indicator showing healthy/degraded/critical state. The bar should answer "is my system healthy?" in under 1 second.

## Files to Modify

- `apps/client/src/layers/features/relay/ui/RelayHealthBar.tsx`
- `apps/client/src/layers/features/relay/ui/__tests__/RelayHealthBar.test.tsx`

## Implementation

### Status Computation

Add a `computeHealthState` function:

```typescript
type HealthState = 'healthy' | 'degraded' | 'critical';

function computeHealthState(
  metrics: DeliveryMetrics,
  connected: number,
  total: number,
): { state: HealthState; message: string } {
  const failureRate = metrics.totalMessages > 0
    ? (metrics.failedCount + metrics.deadLetteredCount) / metrics.totalMessages
    : 0;

  if (total === 0) {
    return { state: 'healthy', message: 'No connections configured' };
  }

  if (failureRate > 0.5 || connected === 0) {
    const pct = Math.round(failureRate * 100);
    return {
      state: 'critical',
      message: `${pct}% failure rate \u2014 ${metrics.failedCount} messages failed today`,
    };
  }

  if (connected < total || failureRate >= 0.05) {
    const disconnected = total - connected;
    if (disconnected > 0) {
      return {
        state: 'degraded',
        message: `${disconnected} connection${disconnected > 1 ? 's' : ''} disconnected`,
      };
    }
    return {
      state: 'degraded',
      message: `${metrics.failedCount} failures in last 24h`,
    };
  }

  return {
    state: 'healthy',
    message: `${connected} connection${connected > 1 ? 's' : ''} active`,
  };
}
```

